import sys, struct
# Attempt to parse PNG chunks to find tEXt/iTXt/zTXt metadata texts
# Reference: PNG file format
path = '/app/code.png'
texts = []
with open(path, 'rb') as f:
    sig = f.read(8)
    if sig != b'\x89PNG\r\n\x1a\n':
        print('Not a PNG signature', sig)
    while True:
        data = f.read(8)
        if len(data) < 8:
            break
        length, ctype = struct.unpack('>I4s', data)
        chunk = f.read(length)
        crc = f.read(4)
        if ctype in (b'tEXt', b'iTXt', b'zTXt'):
            try:
                texts.append((ctype.decode(), chunk))
            except Exception:
                texts.append((ctype, chunk))
        if ctype == b'IEND':
            break

out_lines = []
for ct, ch in texts:
    if ct == 'tEXt':
        try:
            out_lines.append(ch.decode('latin1'))
        except Exception:
            out_lines.append(str(ch))
    elif ct == 'iTXt':
        # iTXt: keyword\0 compression_flag\0 compression_method\0 language_tag\0 translated_keyword\0 text
        parts = ch.split(b'\x00', 5)
        if len(parts) == 6:
            text = parts[5]
        else:
            text = ch
        try:
            out_lines.append(text.decode('utf-8', 'replace'))
        except Exception:
            out_lines.append(str(text))
    elif ct == 'zTXt':
        # zTXt: keyword\0 compression_method compressed_text
        parts = ch.split(b'\x00', 2)
        if len(parts) == 3:
            import zlib
            try:
                out_lines.append(zlib.decompress(parts[2]).decode('latin1'))
            except Exception as e:
                out_lines.append('zTXt decompress error: '+str(e))
        else:
            out_lines.append(str(ch))

if out_lines:
    print('\n'.join(out_lines))
else:
    print('No text chunks found')
